<script setup lang="ts">import {computed,onMounted} from 'vue';import {ArrowRight,Check,Download,Plus,TrendCharts,Warning} from '@element-plus/icons-vue';import {useMerchantStore} from '../stores/merchant';const merchant=useMerchantStore();const demoActivity=[{ref:'AB-249142',type:'Deposit',customer:'091•••8988',amount:'+ ETB 2,000.00',status:'success',time:'24 sec ago'},{ref:'WD-38210',type:'Withdrawal',customer:'092•••4697',amount:'− ETB 1,500.00',status:'success',time:'1 min ago'},{ref:'BN-981234',type:'Deposit',customer:'092•••5510',amount:'+ ETB 750.00',status:'pending',time:'3 min ago'},{ref:'WD-38204',type:'Withdrawal',customer:'097•••3321',amount:'− ETB 875.00',status:'unknown',time:'12 min ago'}];const activity=computed(()=>merchant.demoMode?demoActivity:merchant.transactions.slice(0,8).map(item=>({ref:item.reference,type:item.kind==='deposit'?'Deposit':'Withdrawal',customer:item.customer_phone,amount:`${item.kind==='deposit'?'+':'−'} ETB ${item.amount}`,status:item.p2p_status,time:new Date(item.created_at).toLocaleTimeString()})));const depositTotal=computed(()=>merchant.transactions.filter(x=>x.kind==='deposit'&&x.status==='success').reduce((sum,x)=>sum+Number(x.credited_amount??x.amount),0));const withdrawalTotal=computed(()=>merchant.transactions.filter(x=>x.kind==='withdrawal'&&x.status==='success').reduce((sum,x)=>sum+Number(x.amount),0));const successRate=computed(()=>merchant.transactions.length?`${(merchant.transactions.filter(x=>x.status==='success').length/merchant.transactions.length*100).toFixed(1)}%`:'—');const reviewCount=computed(()=>merchant.transactions.filter(x=>['unknown','manual_review'].includes(x.p2p_status)).length);onMounted(()=>merchant.refresh());</script>
<template><div class="page"><div class="page-heading"><div><p class="eyebrow">{{merchant.environment}} account</p><h1>Welcome back, {{merchant.identity?.user.display_name}}</h1><span class="muted">{{merchant.identity?.merchant.name}} balances, transactions and integration health.</span></div><div class="toolbar"><el-button :icon="Download">Export</el-button><el-button type="primary" :icon="Plus" @click="$router.push('/topups')">Top up liquidity</el-button></div></div>
<section class="balance-card"><div><span>Available balance</span><strong>ETB {{merchant.summary.available}}</strong><small><el-icon><Check/></el-icon> Available for customer withdrawals</small></div><dl><div><dt>Reserved</dt><dd>ETB {{merchant.summary.reserved}}</dd></div><div><dt>Pending</dt><dd>ETB {{merchant.summary.pending}}</dd></div><div><dt>Physical liquidity</dt><dd class="healthy">{{merchant.summary.physicalLiquidity}}</dd></div></dl><div class="motif"><i/><i/><i/></div></section>
<section class="grid grid-4 stats"><article class="panel"><span>Loaded successful deposits</span><strong>ETB {{merchant.demoMode?'1.82M':depositTotal.toLocaleString('en',{minimumFractionDigits:2})}}</strong><small>Latest {{merchant.transactions.length||'demo'}} records</small></article><article class="panel"><span>Loaded successful withdrawals</span><strong>ETB {{merchant.demoMode?'1.31M':withdrawalTotal.toLocaleString('en',{minimumFractionDigits:2})}}</strong><small>Current environment</small></article><article class="panel"><span>Success rate</span><strong>{{merchant.demoMode?'99.1%':successRate}}</strong><small>Loaded records</small></article><article class="panel"><span>Needs review</span><strong>{{merchant.demoMode?'1':reviewCount}}</strong><small>Unknown or manual review</small></article></section>
<section class="grid main-grid"><article class="panel"><div class="panel-head"><div><h2>Volume</h2><span class="muted small">{{merchant.demoMode?'Deposits and withdrawals · 7 days':'Latest authenticated transaction window'}}</span></div><el-tag v-if="!merchant.demoMode">{{merchant.environment}}</el-tag><el-select v-else model-value="7d" size="small" style="width:105px"><el-option label="7 days" value="7d"/></el-select></div><div v-if="merchant.demoMode" class="panel-body chart"><div v-for="(h,i) in [42,62,48,74,58,86,71]" :key="i" class="day"><div><i :style="{height:`${h}%`}"/><b :style="{height:`${h*.72}%`}"/></div><span>{{['Thu','Fri','Sat','Sun','Mon','Tue','Wed'][i]}}</span></div></div><div v-if="merchant.demoMode" class="legend"><span><i/> Deposits ETB 10.82M</span><span><i/> Withdrawals ETB 7.60M</span></div><div v-else class="panel-body live-volume"><div><span>Successful deposits</span><strong>ETB {{depositTotal.toLocaleString('en',{minimumFractionDigits:2})}}</strong></div><div><span>Successful withdrawals</span><strong>ETB {{withdrawalTotal.toLocaleString('en',{minimumFractionDigits:2})}}</strong></div><small>Calculated from the latest {{merchant.transactions.length}} records returned by the merchant-scoped API.</small></div></article>
<article class="panel health"><div class="panel-head"><div><h2>Account health</h2><span class="muted small">Authenticated checks</span></div><el-icon><TrendCharts/></el-icon></div><div class="panel-body"><div><i class="good"><Check/></i><span><strong>API connectivity</strong><small>{{merchant.demoMode?'Operational · 98 ms median':'Portal session authenticated'}}</small></span></div><div><i class="good"><Check/></i><span><strong>Webhook delivery</strong><small>{{merchant.demoMode?'99.99% delivered · no backlog':'Open Webhooks for current delivery logs'}}</small></span></div><div><i class="good"><Check/></i><span><strong>Physical liquidity</strong><small>{{merchant.summary.physicalLiquidity}} capacity for this merchant</small></span></div><div><i class="warn"><Warning/></i><span><strong>{{merchant.demoMode?'One':reviewCount}} transaction{{reviewCount===1?'':'s'}} need review</strong><small>Platform operations controls financial resolution</small></span></div></div></article></section>
<section class="panel activity"><div class="panel-head"><div><h2>Recent transactions</h2><span class="muted small">Latest account activity</span></div><el-button text type="primary" @click="$router.push('/transactions')">View all <el-icon><ArrowRight/></el-icon></el-button></div><div class="table-wrap"><el-table :data="activity"><el-table-column prop="ref" label="Reference" min-width="140"><template #default="s"><strong>{{s.row.ref}}</strong><div class="muted small">{{s.row.type}}</div></template></el-table-column><el-table-column prop="customer" label="Customer" min-width="130"/><el-table-column label="Amount" width="150"><template #default="s"><b :class="['amount',s.row.type==='Deposit'?'positive':'']">{{s.row.amount}}</b></template></el-table-column><el-table-column label="Status" width="125"><template #default="s"><span :class="`status status-${s.row.status}`">{{s.row.status}}</span></template></el-table-column><el-table-column prop="time" label="Time" width="110"/></el-table></div></section></div></template>
