pan{font-size:9px;color:var(--muted)}.legend{display:flex;gap:20px;padding:0 21px 18px;font-size:9px;color:var(--muted)}.legend i{display:inline-block;width:7px;height:7px;border-radius:2px;background:#5c5fde;margin-right:5px}.legend span:nth-child(2) i{background:#34b39e}.health .panel-head>.el-icon{font-size:23px;color:var(--primary)}.health .panel-body>div{display:flex;gap:11px;padding:13px 0;border-bottom:1px solid var(--line)}.health .panel-body>div:last-child{border:0}.health i{width:28px;height:28px;border-radius:8px;display:grid;place-items:center;font-style:normal}.health i.good{background:#e7f7f3;color:var(--teal)}.health i.warn{background:#fff3df;color:#ba7112}.health strong,.health small{display:block}.health strong{font-size:11px}.health small{font-size:9px;color:var(--muted);margin-top:3px}.positive{color:var(--teal)}@media(max-width:950px){.main-grid{grid-template-columns:1fr}.balance-card{grid-template-columns:1fr;gap:20px}}@media(max-width:650px){.balance-card{padding:22px}.balance-card>div:first-child strong{font-size:25px}.balance-card dl{grid-template-columns:1fr 1fr}.balance-card dl div:nth-child(3){margin-top:15px}.chart{height:190px}.day>div{height:150px}}
